  ('fire-eq-tech-moex-03204', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '按防焰性能試驗基準之用語定義，自點火時間終了起，試樣之火焰繼續燃燒之時間，稱為：', '["餘燃時間", "餘焰時間", "碳化時間", "接焰時間"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03205', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備設置標準」規定，5層或6層建築物總樓地板面積在多少平方公尺以上者，應 設置連結送水管？', '["6000", "7000", "8000", "9000"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03206', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備檢修及申報作業基準」規定，火警自動警報設備之第二種離子式局限型偵煙 探測器進行性能檢查，從加煙後到動作之時間應在多少秒內？', '["10", "30", "60", "90"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03207', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備檢修及申報作業基準」規定，下列有關自動撒水設備之綜合檢查何者正確？', '["密閉式撒水設備以幫浦方式之末端查驗管放水壓力應在2.5kgf/cm2以上10kgf/cm2以下", "補助撒水栓放水量應在80L/min以上", "補助撒水栓以幫浦方式之末端查驗管放水壓力應在1kgf/cm2以上10kgf/cm2以下", "補助撒水栓之放水試驗，有關放水壓力之測試，當測量瞄子直線放水壓力時，應將壓力表之進水口， 放置於瞄子前端瞄子口徑的二分之一距離處"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03208', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備檢修及申報作業基準」規定，下列有關避難器具之綜合檢查何者錯誤？', '["緩降機平均的降落速度應在80cm/sec至100cm/sec", "緩降機最大下降速度應在250cm/sec以內", "避難梯為懸吊型者，牆壁與橫桿之間隔應有10cm以上", "避難梯為固定收藏型者，下降時梯柱及橫桿應無明顯地搖動"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03209', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依「各類場所消防安全設備設置標準」規定，顯著滅火困難場所，係指室內儲存場所儲存公共危險物品 達管制量多少倍以上者？', '["100", "120", "140", "150"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "ecb616435b24", "answer_pdf_sha1": "794cf96c9a0b", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
